"use client"

import * as React from "react"

import { cn } from "@/lib/utils"

function TableComponent({
  className,
  ...props
}: React.ComponentProps<"table">) {
  return (
    <table
      data-slot="table"
      className={cn("w-full caption-bottom text-sm", className)}
      {...props}
    />
  )
}

function Table({ className, ...props }: React.ComponentProps<"table">) {
  return (
    <div
      data-slot="table-container"
      className="relative w-full overflow-x-auto"
    >
      <TableComponent className={className} {...props} />
    </div>
  )
}

function TableHeader({ className, ...props }: React.ComponentProps<"thead">) {
  return (
    <thead
      data-slot="table-header"
      className={cn("[&_tr]:border-b", className)}
      {...props}
    />
  )
}

function TableBody({ className, ...props }: React.ComponentProps<"tbody">) {
  return (
    <tbody
      data-slot="table-body"
      className={cn("[&_tr:last-child]:border-0", className)}
      {...props}
    />
  )
}

function TableFooter({ className, ...props }: React.ComponentProps<"tfoot">) {
  return (
    <tfoot
      data-slot="table-footer"
      className={cn(
        "border-t bg-muted/50 font-medium [&>tr]:last:border-b-0",
        className,
      )}
      {...props}
    />
  )
}

function TableRow({ className, ...props }: React.ComponentProps<"tr">) {
  return (
    <tr
      data-slot="table-row"
      className={cn(
        "border-b transition-colors hover:bg-muted/50 data-[state=selected]:bg-muted",
        className,
      )}
      {...props}
    />
  )
}

function TableHead({ className, ...props }: React.ComponentProps<"th">) {
  return (
    <th
      data-slot="table-head"
      className={cn(
        "h-10 px-2 text-left align-middle font-medium whitespace-nowrap text-foreground [&:has([role=checkbox])]:pr-0 *:[[role=checkbox]]:translate-y-[2px]",
        className,
      )}
      {...props}
    />
  )
}

function TableCell({ className, ...props }: React.ComponentProps<"td">) {
  return (
    <td
      data-slot="table-cell"
      className={cn(
        "p-2 align-middle whitespace-nowrap [&:has([role=checkbox])]:pr-0 *:[[role=checkbox]]:translate-y-[2px]",
        className,
      )}
      {...props}
    />
  )
}

function TableCaption({
  className,
  ...props
}: React.ComponentProps<"caption">) {
  return (
    <caption
      data-slot="table-caption"
      className={cn("mt-4 text-sm text-muted-foreground", className)}
      {...props}
    />
  )
}

export {
  TableComponent,
  Table,
  TableHeader,
  TableBody,
  TableFooter,
  TableHead,
  TableRow,
  TableCell,
  TableCaption,
}

"use client"

/**
 * niko-table — created by Semir N. (Semkoo, https://github.com/Semkoo) with AI assistance.
 *
 * Before reporting anything: please check the changelog first.
 *  - In-repo: ./CHANGELOG.md
 *  - Docs site: https://niko-table.com/changelog
 *
 * Found a bug or have a fix? Open an issue or PR on GitHub so other
 * users (and future LLMs reading this code) benefit:
 * https://github.com/Semkoo/niko-table-registry
 */
import React from "react"
import { cn } from "@/lib/utils"
import { TableComponent } from "@/components/ui/table"

/**
 * Extracts height from Tailwind arbitrary values (e.g., h-[600px], max-h-[400px]).
 * Converts them to inline styles to ensure scroll events work reliably.
 * For other height utilities, use the height/maxHeight props directly.
 */
function parseHeightFromClassName(className?: string) {
  if (!className)
    return { height: undefined, maxHeight: undefined, safeClassName: className }

  const classes = className.split(/\s+/)
  let height: string | undefined
  let maxHeight: string | undefined
  const remainingClasses: string[] = []

  for (const cls of classes) {
    // Match arbitrary values: h-[600px], max-h-[400px]
    const heightMatch = cls.match(/^h-\[([^\]]+)\]$/)
    const maxHeightMatch = cls.match(/^max-h-\[([^\]]+)\]$/)

    if (heightMatch) {
      height = heightMatch[1]
    } else if (maxHeightMatch) {
      maxHeight = maxHeightMatch[1]
    } else {
      remainingClasses.push(cls)
    }
  }

  return {
    height,
    maxHeight,
    safeClassName: remainingClasses.join(" "),
  }
}

export interface DataTableContainerProps {
  children: React.ReactNode
  /**
   * Additional CSS classes for the container.
   * Arbitrary height values (e.g., h-[600px], max-h-[400px]) are automatically extracted
   * and applied as inline styles to ensure scroll event callbacks work reliably.
   * For other height utilities, use the height/maxHeight props directly.
   */
  className?: string
  /**
   * Sets the height of the table container.
   * When provided, enables vertical scrolling and allows DataTableBody/DataTableVirtualizedBody
   * to use onScroll, onScrolledTop, and onScrolledBottom callbacks.
   * Takes precedence over height utilities in className.
   */
  height?: number | string
  /**
   * Sets the maximum height of the table container.
   * Defaults to the height value if not specified.
   * Takes precedence over max-height utilities in className.
   */
  maxHeight?: number | string
}

/**
 * DataTable container component that wraps the table and provides scrolling behavior.
 *
 * @example
 * Without height - table grows with content, no scroll
 * <DataTable>
 *   <DataTableHeader />
 *   <DataTableBody />
 * </DataTable>
 *
 * @example
 * With height prop - enables scrolling and scroll event callbacks
 * <DataTable height={600}>
 *   <DataTableHeader />
 *   <DataTableBody
 *     onScroll={(e) => console.log(`Scrolled ${e.percentage}%`)}
 *     onScrolledBottom={() => console.log('Load more data')}
 *   />
 * </DataTable>
 *
 * @example
 * With arbitrary height in className - automatically extracted and applied as inline style
 * <DataTable className="h-[600px]">
 *   <DataTableBody onScroll={...} />
 * </DataTable>
 *
 * @example
 * Prefer using height prop for better type safety and clarity
 * <DataTable height="600px" className="rounded-lg">
 *   <DataTableBody onScroll={...} />
 * </DataTable>
 */
export function DataTable({
  children,
  className,
  height,
  maxHeight,
}: DataTableContainerProps) {
  // Parse height from className if not provided via props
  const parsed = React.useMemo(
    () => parseHeightFromClassName(className),
    [className],
  )

  const finalHeight = height ?? parsed.height
  const finalMaxHeight = maxHeight ?? parsed.maxHeight ?? finalHeight

  return (
    <div
      data-slot="table-container"
      className={cn(
        "relative w-full overflow-auto rounded-lg border",
        // Custom scrollbar styling to match ScrollArea aesthetic
        // Scrollbar visible but subtle by default, more prominent on hover
        "[&::-webkit-scrollbar]:h-2.5 [&::-webkit-scrollbar]:w-2.5",
        "[&::-webkit-scrollbar-track]:bg-transparent",
        "[&::-webkit-scrollbar-thumb]:rounded-full [&::-webkit-scrollbar-thumb]:bg-border/40",
        "hover:[&::-webkit-scrollbar-thumb]:bg-border",
        "[&::-webkit-scrollbar-thumb:hover]:bg-border/80!",
        // Firefox scrollbar styling
        "scrollbar-thin scrollbar-thumb-border/40 scrollbar-track-transparent",
        "hover:scrollbar-thumb-border",
        parsed.safeClassName,
      )}
      style={{
        height: finalHeight,
        maxHeight: finalMaxHeight,
      }}
    >
      <TableComponent>{children}</TableComponent>
    </div>
  )
}

DataTable.displayName = "DataTable"

"use client"

/**
 * niko-table — created by Semir N. (Semkoo, https://github.com/Semkoo) with AI assistance.
 *
 * Before reporting anything: please check the changelog first.
 *  - In-repo: ./CHANGELOG.md
 *  - Docs site: https://niko-table.com/changelog
 *
 * Found a bug or have a fix? Open an issue or PR on GitHub so other
 * users (and future LLMs reading this code) benefit:
 * https://github.com/Semkoo/niko-table-registry
 */
import {
  getCoreRowModel,
  getExpandedRowModel,
  getFacetedMinMaxValues,
  getFacetedRowModel,
  getFacetedUniqueValues,
  getFilteredRowModel,
  getPaginationRowModel,
  getSortedRowModel,
  useReactTable,
  type ColumnFiltersState,
  type ColumnOrderState,
  type ColumnSizingState,
  type ExpandedState,
  type FilterFn,
  type FilterFnOption,
  type PaginationState,
  type RowSelectionState,
  type SortingState,
  type Table,
  type TableOptions,
  type Updater,
  type VisibilityState,
} from "@tanstack/react-table"
import { TooltipProvider } from "@/components/ui/tooltip"
import { cn } from "@/lib/utils"
import React from "react"
import { detectFeaturesFromChildren } from "../config/feature-detection"
import {
  DEFAULT_MIN_COLUMN_SIZE,
  FILTER_VARIANTS,
  SYSTEM_COLUMN_IDS,
  SYSTEM_COLUMN_ID_LIST,
} from "../lib/constants"
import {
  dateRangeFilter,
  extendedFilter,
  globalFilter as globalFilterFn,
  numberRangeFilter,
} from "../lib/filter-functions"
import { type DataTableColumnDef, type GlobalFilter } from "../types"
import { DataTableProvider } from "./data-table-context"

/**
 * Delay (ms) before a tooltip inside a data table opens. Deliberately long so
 * header help/sort tooltips don't pop while the assigner is scanning or
 * clicking through sorts — they only appear on a considered hover. Scopes to
 * the table via a nested `TooltipProvider`, so action-button tooltips outside
 * the table keep their own (faster) provider delay.
 */
const TABLE_TOOLTIP_DELAY_MS = 1000

export interface DataTableConfig {
  // Feature toggles
  enablePagination?: boolean
  enableFilters?: boolean
  enableSorting?: boolean
  enableRowSelection?: boolean
  enableMultiSort?: boolean
  enableGrouping?: boolean
  enableExpanding?: boolean
  /**
   * Enable drag-to-resize column widths (opt-in; off by default so existing
   * tables are unaffected). When on, columns render at `column.getSize()` and a
   * resize handle appears on each resizable header's right edge. Drop
   * `<DataTableColumnResize />` inside the root to enable via feature detection.
   * Double-click a grip to autosize; columns opt out with `enableResizing: false`.
   */
  enableColumnResizing?: boolean

  // Manual modes (for server-side)
  manualSorting?: boolean
  manualPagination?: boolean
  manualFiltering?: boolean
  pageCount?: number

  // Initial state
  initialPageSize?: number
  initialPageIndex?: number

  // Auto-reset behaviors
  autoResetPageIndex?: boolean
  autoResetExpanded?: boolean
}

interface TableRootProps<TData, TValue> extends Partial<TableOptions<TData>> {
  // Option 1: Pass a pre-configured table instance
  table?: Table<TData>

  // Option 2: Let DataTableRoot create its own table
  columns?: DataTableColumnDef<TData, TValue>[]
  data?: TData[]

  children: React.ReactNode
  className?: string

  // Configuration object
  config?: DataTableConfig
  getRowId?: (originalRow: TData, index: number) => string

  // Loading state
  isLoading?: boolean

  // Event handlers
  onGlobalFilterChange?: (value: GlobalFilter) => void
  onPaginationChange?: (updater: Updater<PaginationState>) => void
  onSortingChange?: (updater: Updater<SortingState>) => void
  onColumnVisibilityChange?: (updater: Updater<VisibilityState>) => void
  onColumnFiltersChange?: (updater: Updater<ColumnFiltersState>) => void
  onRowSelectionChange?: (updater: Updater<RowSelectionState>) => void
  onExpandedChange?: (updater: Updater<ExpandedState>) => void
  onColumnOrderChange?: (updater: Updater<ColumnOrderState>) => void
  onRowSelection?: (selectedRows: TData[]) => void
}

// Internal component that handles hooks for direct props mode
function DataTableRootInternal<TData, TValue>({
  columns,
  data,
  children,
  className,
  config,
  getRowId,
  isLoading,
  onGlobalFilterChange,
  onPaginationChange,
  onSortingChange,
  onColumnVisibilityChange,
  onColumnFiltersChange,
  onRowSelectionChange,
  onExpandedChange,
  onColumnOrderChange,
  onColumnPinningChange,
  onColumnSizingChange,
  onRowSelection,
  // Destructured by name so the `tableOptions` memo depends on stable values
  // — depending on the whole `rest` bag invalidated the memo every render
  // and triggered the "state update on a component that hasn't mounted yet"
  // warning under React 19 + Strict Mode + Turbopack HMR.
  state: restState,
  initialState: restInitialState,
  globalFilterFn: restGlobalFilterFn,
  // Spread into `tableOptions` but NOT in the memo deps. Lift any passthrough
  // option that needs to invalidate the memo into the destructure list above.
  ...passthroughTableOptions
}: Omit<TableRootProps<TData, TValue>, "table"> & {
  columns: DataTableColumnDef<TData, TValue>[]
  data: TData[]
}) {
  // Memoize so `columns.some()` only runs when the columns array changes.
  const hasSelectColumn = React.useMemo(
    () => columns?.some(col => col.id === SYSTEM_COLUMN_IDS.SELECT) ?? false,
    [columns],
  )

  const hasExpandColumn = React.useMemo(
    () =>
      columns?.some(
        col =>
          col.id === SYSTEM_COLUMN_IDS.EXPAND ||
          (col.meta &&
            "expandedContent" in col.meta &&
            col.meta.expandedContent),
      ) ?? false,
    [columns],
  )

  // Stable identity prevents downstream memo cascades (detectFeatures,
  // processedColumns, tableOptions) from invalidating each render.
  const finalConfig: DataTableConfig = React.useMemo(
    () => ({
      enablePagination: config?.enablePagination,
      enableFilters: config?.enableFilters,
      enableSorting: config?.enableSorting,
      enableRowSelection: config?.enableRowSelection ?? hasSelectColumn,
      enableMultiSort: config?.enableMultiSort,
      enableGrouping: config?.enableGrouping,
      enableExpanding: config?.enableExpanding ?? hasExpandColumn,
      enableColumnResizing: config?.enableColumnResizing,
      manualSorting: config?.manualSorting,
      manualPagination: config?.manualPagination,
      manualFiltering: config?.manualFiltering,
      pageCount: config?.pageCount,
      initialPageSize: config?.initialPageSize,
      initialPageIndex: config?.initialPageIndex,
      // Default `false` — preserves pagination cursor across filter changes
      // (better UX for server-side / infinite scroll) and avoids the async
      // `onPaginationChange` race that fires "state update on unmounted
      // component" warnings. Opt in via `config={{ autoResetPageIndex: true }}`.
      autoResetPageIndex: config?.autoResetPageIndex ?? false,
      autoResetExpanded: config?.autoResetExpanded ?? false,
    }),
    [
      config?.enablePagination,
      config?.enableFilters,
      config?.enableSorting,
      config?.enableRowSelection,
      hasSelectColumn,
      config?.enableMultiSort,
      config?.enableGrouping,
      config?.enableExpanding,
      config?.enableColumnResizing,
      hasExpandColumn,
      config?.manualSorting,
      config?.manualPagination,
      config?.manualFiltering,
      config?.pageCount,
      config?.initialPageSize,
      config?.initialPageIndex,
      config?.autoResetPageIndex,
      config?.autoResetExpanded,
    ],
  )

  // Cache once: `detectFeaturesFromChildren` recursively walks the React tree
  // (50-150ms on deep trees). Children structure is stable post-mount.
  const detectedFeaturesRef = React.useRef<ReturnType<
    typeof detectFeaturesFromChildren
  > | null>(null)

  // Only detect features once on mount (children structure is stable)
  if (detectedFeaturesRef.current === null) {
    detectedFeaturesRef.current = detectFeaturesFromChildren(children, columns)
  }

  // Memoize merged feature object so tableOptions stays stable.
  const detectFeatures = React.useMemo(() => {
    const detectedFeatures = detectedFeaturesRef.current ?? {}

    const features = {
      // Use config first, then explicit props, then detected features, then defaults
      enablePagination:
        finalConfig.enablePagination ??
        detectedFeatures.enablePagination ??
        false,
      enableFilters:
        finalConfig.enableFilters ?? detectedFeatures.enableFilters ?? false,
      enableRowSelection:
        finalConfig.enableRowSelection ??
        detectedFeatures.enableRowSelection ??
        false,
      enableSorting:
        finalConfig.enableSorting ?? detectedFeatures.enableSorting ?? false,
      enableMultiSort:
        finalConfig.enableMultiSort ?? detectedFeatures.enableMultiSort ?? true,
      enableGrouping:
        finalConfig.enableGrouping ?? detectedFeatures.enableGrouping ?? true,
      enableExpanding:
        finalConfig.enableExpanding ??
        detectedFeatures.enableExpanding ??
        false,
      enableColumnResizing:
        finalConfig.enableColumnResizing ??
        detectedFeatures.enableColumnResizing ??
        false,
      manualSorting:
        finalConfig.manualSorting ?? detectedFeatures.manualSorting ?? false,
      manualPagination:
        finalConfig.manualPagination ??
        detectedFeatures.manualPagination ??
        false,
      manualFiltering:
        finalConfig.manualFiltering ??
        detectedFeatures.manualFiltering ??
        false,
      pageCount: finalConfig.pageCount ?? detectedFeatures.pageCount,
    }

    return features
  }, [finalConfig])

  // State management
  const [globalFilter, setGlobalFilter] = React.useState<GlobalFilter>(
    restInitialState?.globalFilter ?? "",
  )
  const [rowSelection, setRowSelection] = React.useState<RowSelectionState>(
    restInitialState?.rowSelection ?? {},
  )
  const [columnVisibility, setColumnVisibility] =
    React.useState<VisibilityState>(restInitialState?.columnVisibility ?? {})
  const [columnFilters, setColumnFilters] = React.useState<ColumnFiltersState>(
    restInitialState?.columnFilters ?? [],
  )
  const [sorting, setSorting] = React.useState<SortingState>(
    restInitialState?.sorting ?? [],
  )
  const [expanded, setExpanded] = React.useState<ExpandedState>(
    restInitialState?.expanded ?? {},
  )
  const [columnPinning, setColumnPinning] = React.useState<{
    left: string[]
    right: string[]
  }>({
    left: restInitialState?.columnPinning?.left ?? [],
    right: restInitialState?.columnPinning?.right ?? [],
  })
  const [columnOrder, setColumnOrder] = React.useState<ColumnOrderState>(
    restInitialState?.columnOrder ?? [],
  )
  const [columnSizing, setColumnSizing] = React.useState<ColumnSizingState>(
    restInitialState?.columnSizing ?? {},
  )
  const [pagination, setPagination] = React.useState<PaginationState>({
    pageIndex:
      finalConfig.initialPageIndex ??
      restInitialState?.pagination?.pageIndex ??
      0,
    pageSize:
      finalConfig.initialPageSize ??
      restInitialState?.pagination?.pageSize ??
      10,
  })

  // Mount-ref guards prevent React-19 + StrictMode "state update on unmounted
  // component" warnings when TanStack's async dispatches land on a torn-down fiber.
  const isMountedRef = React.useRef(true)
  React.useEffect(() => {
    isMountedRef.current = true
    return () => {
      isMountedRef.current = false
    }
  }, [])

  // Stable identity keeps tableOptions memo from invalidating each render.
  const handleGlobalFilterChange = React.useCallback(
    (value: GlobalFilter) => {
      // Mount-guard local writes; external handler is caller's responsibility.
      if (isMountedRef.current) {
        setGlobalFilter(value)
      }
      onGlobalFilterChange?.(value)
    },
    [onGlobalFilterChange],
  )

  // O(1) row-by-id lookup; Array.find()-per-selection is O(n × m) — ~500ms lag
  // at 10k rows × 100 selected.
  const rowIdMap = React.useMemo(() => {
    const map = new Map<string, TData>()
    data?.forEach((row, idx) => {
      const rowId =
        getRowId?.(row, idx) ??
        (row as { id?: string | number }).id?.toString() ??
        String(idx)
      map.set(rowId, row)
    })
    return map
  }, [data, getRowId])

  // Stable identity prevents table re-init. Pure setter — `onRowSelection`
  // fires from the effect below so concurrent-mode double-invokes don't double-fire.
  // Honors the full TanStack `Updater<T> = T | ((old: T) => T)` contract.
  const handleRowSelectionChange = React.useCallback(
    (valueFn: Updater<RowSelectionState>) => {
      if (!isMountedRef.current) return
      if (typeof valueFn === "function") {
        setRowSelection(prev => valueFn(prev))
      } else {
        setRowSelection(valueFn)
      }
    },
    [],
  )

  /**
   * PERFORMANCE: Stable mount-guarded fallback setters
   *
   * WHY: Inline `(u) => isMounted && setX(u)` closures inside `tableOptions` get
   * recreated on every memo invalidation, and the 6 setX refs added noise to the
   * dep array (state setters are already stable by React contract).
   *
   * IMPACT: tableOptions memo no longer depends on 6 setters; fallback handlers
   * keep referential identity across renders.
   *
   * WHAT: Hoists each fallback to a `useCallback([])`. Mount-guard preserved so
   * StrictMode-unmounted fibers don't receive setState calls.
   */
  const handleSortingChange = React.useCallback((u: Updater<SortingState>) => {
    if (isMountedRef.current) setSorting(u)
  }, [])

  const handleColumnFiltersChange = React.useCallback(
    (u: Updater<ColumnFiltersState>) => {
      if (isMountedRef.current) setColumnFilters(u)
    },
    [],
  )

  const handleColumnVisibilityChange = React.useCallback(
    (u: Updater<VisibilityState>) => {
      if (isMountedRef.current) setColumnVisibility(u)
    },
    [],
  )

  const handleColumnPinningChange = React.useCallback(
    (updater: Updater<{ left?: string[]; right?: string[] }>) => {
      if (!isMountedRef.current) return
      setColumnPinning(prev => {
        const next = typeof updater === "function" ? updater(prev) : updater
        return {
          left: next.left ?? [],
          right: next.right ?? [],
        }
      })
    },
    [],
  )

  const handleColumnOrderChange = React.useCallback(
    (u: Updater<ColumnOrderState>) => {
      if (isMountedRef.current) setColumnOrder(u)
    },
    [],
  )

  const handleColumnSizingChange = React.useCallback(
    (u: Updater<ColumnSizingState>) => {
      if (isMountedRef.current) setColumnSizing(u)
    },
    [],
  )

  const handleExpandedChange = React.useCallback(
    (u: Updater<ExpandedState>) => {
      if (isMountedRef.current) setExpanded(u)
    },
    [],
  )

  const handlePaginationChange = React.useCallback(
    (u: Updater<PaginationState>) => {
      if (isMountedRef.current) setPagination(u)
    },
    [],
  )

  // Fire `onRowSelection` only on user-driven changes — skip the initial mount.
  const skipInitialRowSelectionRef = React.useRef(true)
  React.useEffect(() => {
    if (!isMountedRef.current) return
    if (skipInitialRowSelectionRef.current) {
      skipInitialRowSelectionRef.current = false
      return
    }
    if (!onRowSelection) return
    const selectedRows = Object.keys(rowSelection)
      .filter(key => rowSelection[key])
      .map(key => rowIdMap.get(key))
      .filter((row): row is TData => row !== undefined)
    onRowSelection(selectedRows)
  }, [rowSelection, rowIdMap, onRowSelection])

  /**
   * Auto-apply filterFn based on meta.variant if not explicitly provided
   * This allows developers to set variant in meta and get the right filterFn automatically
   */
  const processedColumns = React.useMemo(() => {
    return columns.map(col => {
      // If filterFn is already defined, use it (manual override)
      if (col.filterFn) return col

      const meta = col.meta ?? {}
      const variant = meta.variant

      // Auto-apply filterFn based on variant
      let autoFilterFn: FilterFnOption<TData> | undefined
      if (
        variant === FILTER_VARIANTS.RANGE ||
        variant === FILTER_VARIANTS.NUMBER
      ) {
        // For number/range variants, use numberRangeFilter if no explicit filterFn
        autoFilterFn = "numberRange" as FilterFnOption<TData>
      } else if (
        variant === FILTER_VARIANTS.DATE ||
        variant === FILTER_VARIANTS.DATE_RANGE
      ) {
        // For date variants, use dateRangeFilter if no explicit filterFn
        autoFilterFn = "dateRange" as FilterFnOption<TData>
      }

      // Only override if we have an auto filterFn and no explicit one
      if (autoFilterFn) {
        return {
          ...col,
          filterFn: autoFilterFn,
        }
      }

      return col
    })
  }, [columns])

  // TanStack's `defaultColumn` is per-render-cheaper than mapping columns ourselves.
  const defaultColumn = React.useMemo<Partial<DataTableColumnDef<TData>>>(
    () => ({
      // Follow table-level sorting detection — don't opt every column into
      // sortable chrome when sorting is off.
      enableSorting: detectFeatures.enableSorting ?? false,
      enableHiding: true,
      filterFn: "extended" as FilterFnOption<TData>,
      // Override TanStack's internal default (150) so unset `size` stays undefined
      // — virtualized flex layout uses this to distinguish fixed vs flexible cols.
      // `column.getSize()` still falls back to 150 internally.
      size: undefined,
      // Align mouse-drag floor with the resize handle's keyboard/autosize
      // clamp (TanStack's built-in default is 20 — too tight for padded cells).
      ...(detectFeatures.enableColumnResizing
        ? { minSize: DEFAULT_MIN_COLUMN_SIZE }
        : {}),
    }),
    [detectFeatures.enableColumnResizing, detectFeatures.enableSorting],
  )

  // Extract controlled-state slices for the tableOptions dep array.
  const controlledSorting = restState?.sorting ?? sorting
  const controlledColumnVisibility =
    restState?.columnVisibility ?? columnVisibility
  const controlledRowSelection = restState?.rowSelection ?? rowSelection
  const controlledColumnFilters = restState?.columnFilters ?? columnFilters
  const controlledGlobalFilter =
    restState?.globalFilter !== undefined
      ? restState.globalFilter
      : globalFilter
  const controlledColumnPinning = restState?.columnPinning ?? columnPinning
  const controlledColumnOrder = restState?.columnOrder ?? columnOrder
  const controlledColumnSizing = restState?.columnSizing ?? columnSizing
  const controlledExpanded = restState?.expanded ?? expanded
  const controlledPagination = restState?.pagination ?? pagination

  // System columns (select, expand) follow the first data column's pinning so
  // they stay visually attached as the "row header".
  const finalColumnPinning = React.useMemo(() => {
    // Use centralized system column IDs from constants

    // Helper to safely extract column ID (handles both id and accessorKey)
    const getColumnId = (
      col: DataTableColumnDef<TData, TValue>,
    ): string | undefined => {
      if (col.id) return col.id
      // Type-safe check for accessorKey property
      if ("accessorKey" in col && typeof col.accessorKey === "string") {
        return col.accessorKey
      }
      return undefined
    }

    // 1. Identify the "First Data Column" (first non-system column)
    const firstDataCol = columns.find(col => {
      const id = getColumnId(col)
      return id && !SYSTEM_COLUMN_ID_LIST.includes(id)
    })

    if (!firstDataCol) return controlledColumnPinning

    const firstDataColId = getColumnId(firstDataCol)
    if (!firstDataColId) return controlledColumnPinning

    // 2. Check pinning state of the first data column
    const isPinnedLeft = controlledColumnPinning.left?.includes(firstDataColId)
    const isPinnedRight =
      controlledColumnPinning.right?.includes(firstDataColId)

    // If not fixed to either side, return default (system cols float naturally)
    if (!isPinnedLeft && !isPinnedRight) {
      return controlledColumnPinning
    }

    const left = [...(controlledColumnPinning.left ?? [])]
    const right = [...(controlledColumnPinning.right ?? [])]

    // 3. Prepare system columns list
    const systemColsPresent: string[] = []
    if (hasSelectColumn) systemColsPresent.push(SYSTEM_COLUMN_IDS.SELECT)
    if (hasExpandColumn) systemColsPresent.push(SYSTEM_COLUMN_IDS.EXPAND)

    // 4. Clean existing lists (remove system cols to avoid duplication)
    const cleanLeft = left.filter(id => !SYSTEM_COLUMN_ID_LIST.includes(id))
    const cleanRight = right.filter(id => !SYSTEM_COLUMN_ID_LIST.includes(id))

    // 5. Construct new pinning state
    if (isPinnedLeft) {
      // Pin Left: [System, ...Others]
      return {
        left: [...systemColsPresent, ...cleanLeft],
        right: cleanRight,
      }
    }

    if (isPinnedRight) {
      // Pin Right: [System, ...Others]
      // We place system cols *before* others in the Right group so they appear
      // to the immediate left of the right-pinned data columns.
      return {
        left: cleanLeft,
        right: [...systemColsPresent, ...cleanRight],
      }
    }

    return controlledColumnPinning
  }, [controlledColumnPinning, columns, hasSelectColumn, hasExpandColumn])

  // Critical: stable options reference. New object → useReactTable recreates
  // the instance → state resets and sorting/filter/expand break.
  const tableOptions = React.useMemo<TableOptions<TData>>(
    () => ({
      ...passthroughTableOptions,
      data,
      columns: processedColumns,
      defaultColumn,
      state: {
        ...restState,
        // Always use our local state as the source of truth
        // External state (restState) takes precedence only if explicitly provided
        sorting: controlledSorting,
        columnVisibility: controlledColumnVisibility,
        columnPinning: finalColumnPinning,
        columnOrder: controlledColumnOrder,
        columnSizing: controlledColumnSizing,
        rowSelection: controlledRowSelection,
        columnFilters: controlledColumnFilters,
        globalFilter: controlledGlobalFilter,
        expanded: controlledExpanded,
        pagination: controlledPagination,
      },
      enableColumnResizing: detectFeatures.enableColumnResizing,
      columnResizeMode: "onChange",
      onColumnSizingChange: onColumnSizingChange ?? handleColumnSizingChange,
      enableRowSelection: detectFeatures.enableRowSelection,
      enableFilters: detectFeatures.enableFilters,
      enableSorting: detectFeatures.enableSorting,
      enableMultiSort: detectFeatures.enableMultiSort,
      enableGrouping: detectFeatures.enableGrouping,
      enableExpanding: detectFeatures.enableExpanding,
      manualSorting: detectFeatures.manualSorting,
      manualPagination: detectFeatures.manualPagination,
      manualFiltering: detectFeatures.manualFiltering,
      // Enable auto-reset behaviors by default (standard TanStack Table behavior)
      // Can be overridden via config
      autoResetPageIndex: finalConfig.autoResetPageIndex,
      autoResetExpanded: finalConfig.autoResetExpanded,
      onGlobalFilterChange: handleGlobalFilterChange,
      onRowSelectionChange: onRowSelectionChange ?? handleRowSelectionChange,
      // Default state setters are mount-ref guarded so TanStack's async
      // auto-reset dispatches don't land on a StrictMode-unmounted fiber.
      // Consumer-supplied handlers are NOT guarded — caller's responsibility.
      onSortingChange: onSortingChange ?? handleSortingChange,
      onColumnFiltersChange: onColumnFiltersChange ?? handleColumnFiltersChange,
      onColumnVisibilityChange:
        onColumnVisibilityChange ?? handleColumnVisibilityChange,
      onColumnPinningChange: onColumnPinningChange ?? handleColumnPinningChange,
      onColumnOrderChange: onColumnOrderChange ?? handleColumnOrderChange,
      onExpandedChange: onExpandedChange ?? handleExpandedChange,
      onPaginationChange: onPaginationChange ?? handlePaginationChange,
      getCoreRowModel: getCoreRowModel(),
      getFacetedRowModel: detectFeatures.enableFilters
        ? getFacetedRowModel()
        : undefined,
      getFacetedUniqueValues: detectFeatures.enableFilters
        ? getFacetedUniqueValues()
        : undefined,
      getFacetedMinMaxValues: detectFeatures.enableFilters
        ? getFacetedMinMaxValues()
        : undefined,
      getFilteredRowModel: detectFeatures.enableFilters
        ? getFilteredRowModel()
        : undefined,
      getSortedRowModel: detectFeatures.enableSorting
        ? getSortedRowModel()
        : undefined,
      getPaginationRowModel: detectFeatures.enablePagination
        ? getPaginationRowModel()
        : undefined,
      getExpandedRowModel: detectFeatures.enableExpanding
        ? getExpandedRowModel()
        : undefined,
      filterFns: {
        extended: extendedFilter,
        numberRange: numberRangeFilter,
        dateRange: dateRangeFilter,
      },
      // Allow globalFilterFn to be overridden via rest props, otherwise use default
      globalFilterFn:
        (restGlobalFilterFn as FilterFn<TData>) ??
        (globalFilterFn as unknown as FilterFn<TData>),
      // Use provided getRowId or fallback to checking for 'id' property, then index
      getRowId:
        getRowId ??
        ((originalRow, index) => {
          // Try to use 'id' property if it exists
          const rowWithId = originalRow as { id?: string | number }
          if (rowWithId.id !== undefined && rowWithId.id !== null) {
            return String(rowWithId.id)
          }
          // Fallback to index
          return String(index)
        }),
      pageCount: (() => {
        if (!detectFeatures.manualPagination) return undefined
        return finalConfig.pageCount !== undefined
          ? finalConfig.pageCount
          : detectFeatures.pageCount !== undefined
            ? detectFeatures.pageCount
            : -1
      })(),
    }),
    // Deps are the *destructured* rest props, NOT the whole rest bag — see
    // destructure-site comment. `passthroughTableOptions` is intentionally
    // NOT a dep (lift any option that needs to invalidate the memo).
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [
      restState,
      restGlobalFilterFn,
      data,
      processedColumns,
      defaultColumn,
      detectFeatures,
      finalConfig,
      handleGlobalFilterChange,
      onRowSelectionChange,
      handleRowSelectionChange,
      onSortingChange,
      handleSortingChange,
      onColumnFiltersChange,
      handleColumnFiltersChange,
      onColumnVisibilityChange,
      handleColumnVisibilityChange,
      onColumnPinningChange,
      handleColumnPinningChange,
      onColumnOrderChange,
      handleColumnOrderChange,
      onColumnSizingChange,
      handleColumnSizingChange,
      onExpandedChange,
      handleExpandedChange,
      onPaginationChange,
      handlePaginationChange,
      getRowId,
      // Use controlled state values - these update when either external or local state changes
      controlledSorting,
      controlledColumnVisibility,
      controlledRowSelection,
      controlledColumnFilters,
      controlledGlobalFilter,
      controlledColumnOrder,
      controlledColumnSizing,
      controlledExpanded,
      controlledPagination,
      // Add column pinning state to dependencies so the table updates when it changes
      finalColumnPinning,
    ],
  )

  // Instance ref is stable across state changes; React Compiler warns about
  // incompatible-library here — TanStack manages its own memoization (expected).

  const table = useReactTable<TData>(tableOptions)

  return (
    <DataTableProvider
      table={table}
      columns={processedColumns as DataTableColumnDef<TData>[]}
      isLoading={isLoading}
    >
      <TooltipProvider delayDuration={TABLE_TOOLTIP_DELAY_MS}>
        <div className={cn("w-full min-w-0 space-y-4", className)}>
          {children}
        </div>
      </TooltipProvider>
    </DataTableProvider>
  )
}

// Main wrapper component
export function DataTableRoot<TData, TValue>({
  table: externalTable,
  columns,
  data,
  children,
  className,
  isLoading,
  ...rest
}: TableRootProps<TData, TValue>) {
  // If a table instance is provided, use it directly (no hooks needed)
  if (externalTable) {
    return (
      <DataTableProvider
        table={externalTable}
        columns={columns as DataTableColumnDef<TData>[]}
        isLoading={isLoading}
      >
        <TooltipProvider delayDuration={TABLE_TOOLTIP_DELAY_MS}>
          <div className={cn("w-full min-w-0 space-y-4", className)}>
            {children}
          </div>
        </TooltipProvider>
      </DataTableProvider>
    )
  }

  // Validate required props for internal table creation
  if (!columns || !data) {
    throw new Error(
      "DataTableRoot: Either provide a 'table' prop or both 'columns' and 'data' props",
    )
  }

  // Otherwise, delegate to the internal component that handles hooks
  return (
    <DataTableRootInternal
      columns={columns}
      data={data}
      className={className}
      isLoading={isLoading}
      {...rest}
    >
      {children}
    </DataTableRootInternal>
  )
}

DataTableRoot.displayName = "DataTableRoot"

"use client"

/**
 * niko-table — created by Semir N. (Semkoo, https://github.com/Semkoo) with AI assistance.
 *
 * Before reporting anything: please check the changelog first.
 *  - In-repo: ./CHANGELOG.md
 *  - Docs site: https://niko-table.com/changelog
 *
 * Found a bug or have a fix? Open an issue or PR on GitHub so other
 * users (and future LLMs reading this code) benefit:
 * https://github.com/Semkoo/niko-table-registry
 */
import React, {
  createContext,
  useCallback,
  useContext,
  useReducer,
} from "react"
import { useGeneratedOptions } from "../hooks/use-generated-options"
import type { DataTableColumnDef, DataTableInstance, Option } from "../types"

export type DataTableContextState = {
  isLoading: boolean
}

/** Alignment for `scrollRowIntoView`, mirroring TanStack Virtual's `align`. */
export type ScrollAlign = "auto" | "start" | "center" | "end"

/** Scroll a row into view by its position in the current row model. */
export type ScrollRowIntoView = (
  index: number,
  opts?: { align?: ScrollAlign },
) => void

/**
 * The active-selection SPAN for a grid-style cross-highlight — EVERY column
 * and row in the current selection lights up (header + gutter), not just the
 * focused cell. Grid-agnostic: the editable grid sets it from its selection
 * rectangle. `null` disables the highlight (the default for read-only tables).
 *
 * Columns are addressed by id (there are few and all render, so a Set is
 * cheap); rows by an inclusive row-model index range (rows are virtualized, so
 * a Set of ids would be unbounded for a large selection — the body tests each
 * visible row's `index` against the range in O(1)).
 */
export interface ActiveSelection {
  /** Ids of columns whose header should highlight. */
  columnIds: ReadonlySet<string>
  /** Inclusive row-model index range whose rows/gutter should highlight. */
  rowRange: { min: number; max: number }
}
export type ActiveCell = ActiveSelection | null

export interface FlashRowsOptions {
  /** How long the highlight lasts, ms. Default 1400. */
  durationMs?: number
  /** Scroll the first flashed row into view first. Default true. */
  scrollIntoView?: boolean
}

/**
 * Briefly highlight rows (by id) so users see what just changed — e.g. after a
 * mutation ("which row did adding a member update?"). Scrolls the row into view
 * (reusing the virtualizer bridge) then plays a soft fade pulse. A row flash
 * lights every cell in the row (works even under pinned columns).
 */
export type FlashRows = (ids: string[], opts?: FlashRowsOptions) => void

/** A single cell target for `flashCells`. */
export interface FlashCellRef {
  rowId: string
  columnId: string
}

/**
 * Briefly highlight individual cells (cell-level, for value-level changes —
 * e.g. an inline edit or paste). Same fade pulse as `flashRows`, scoped to cells.
 */
export type FlashCells = (
  cells: FlashCellRef[],
  opts?: FlashRowsOptions,
) => void

/** Internal key for a flashing cell (row id + column id). */
export function flashCellKey(rowId: string, columnId: string): string {
  return `${rowId}:${columnId}`
}

type DataTableContextProps<TData> = DataTableContextState & {
  table: DataTableInstance<TData>
  columns: DataTableColumnDef<TData>[]
  generatedOptionsMap: Record<string, Option[]>
  setIsLoading: (isLoading: boolean) => void
  /** Ids of rows currently flashing (used by the body to animate them). */
  flashingRowIds: ReadonlySet<string>
  /** Keys (`flashCellKey`) of cells currently flashing. */
  flashingCellKeys: ReadonlySet<string>
  /** Flash rows by id — scroll into view + soft fade pulse. */
  flashRows: FlashRows
  /** Flash individual cells (value-level changes). */
  flashCells: FlashCells
  /**
   * Scroll a row into view. Works on virtualized bodies (via the virtualizer,
   * which registers itself) and plain bodies (DOM `scrollIntoView` fallback).
   * A stable, virtualizer-agnostic handle so consumers never touch the
   * virtualizer directly — the registry owner can change virtualization
   * internals without breaking consumers.
   */
  scrollRowIntoView: ScrollRowIntoView
  /**
   * Internal: the virtualized body registers its scroll function here on mount
   * and clears it (null) on unmount. Non-virtualized bodies never register, so
   * `scrollRowIntoView` falls back to a DOM query.
   */
  registerRowScroller: (fn: ScrollRowIntoView | null) => void
  /**
   * Toggle a row's selection with standard Shift-range support: a plain
   * click toggles one row and sets the anchor; a Shift+click selects every row
   * between the anchor and this one (in current display order). Wire a select
   * checkbox to this instead of `row.toggleSelected()` to get range selection.
   */
  toggleRowSelection: (rowId: string, shiftKey: boolean) => void
}

// ---------------------------------------------------------------------------
// Active-cell cross-highlight — its OWN context pair, deliberately outside the
// main context value. The active cell changes on every keystroke in an
// editable grid; if it lived in the main value, every `useDataTable` consumer
// (toolbar, filters, header, body, empty states) would re-render per arrow
// key. Split out, only the header + body — the two subscribers — re-render,
// and read-only tables (where it stays `null`) never re-render at all.
// ---------------------------------------------------------------------------

const ActiveCellValueContext = createContext<ActiveCell>(null)
const ActiveCellSetterContext = createContext<
  ((cell: ActiveCell) => void) | null
>(null)

/**
 * The active-selection span for the grid-style cross-highlight (`null` when
 * inactive). In a header, `activeCell.columnIds.has(column.id)` lights the
 * active columns; in a body/gutter, the row's **display** index (position in
 * `getRowModel().rows` / the virtualizer index) within `activeCell.rowRange`
 * lights the active rows — not TanStack's source-data `row.index`.
 */
export function useDataTableActiveCell(): ActiveCell {
  return useContext(ActiveCellValueContext)
}

/**
 * Set (or clear, with `null`) the active-cell cross-highlight. The setter is
 * stable, so subscribing to it never causes re-renders. Used by the grid's
 * `<DataGridCrossHighlight>` opt-in.
 */
export function useDataTableActiveCellSetter(): (cell: ActiveCell) => void {
  const setter = useContext(ActiveCellSetterContext)
  if (setter === null) {
    throw new Error(
      "useDataTableActiveCellSetter must be used within DataTableRoot",
    )
  }
  return setter
}

// eslint-disable-next-line @typescript-eslint/no-explicit-any
const DataTableContext = createContext<DataTableContextProps<any> | undefined>(
  undefined,
)

export function useDataTable<TData>(): DataTableContextProps<TData> {
  const context = useContext(DataTableContext)
  if (context === undefined) {
    throw new Error("useDataTable must be used within DataTableRoot")
  }
  return context as DataTableContextProps<TData>
}

export enum DataTableActions {
  SET,
  SET_IS_LOADING,
}

type DataTableAction = {
  type: DataTableActions.SET_IS_LOADING
  value: boolean
}

function dataTableReducer(
  state: DataTableContextState,
  action: DataTableAction,
): DataTableContextState {
  switch (action.type) {
    case DataTableActions.SET_IS_LOADING:
      return { ...state, isLoading: action.value }
    default:
      return state
  }
}

function deriveInitialState(isLoading?: boolean): DataTableContextState {
  return {
    isLoading: isLoading ?? false,
  }
}

interface DataTableProviderProps<TData> {
  children: React.ReactNode
  table: DataTableInstance<TData>
  columns?: DataTableColumnDef<TData>[]
  isLoading?: boolean
}

/**
 * A set of currently-"flashing" string keys with per-key auto-expiry timers.
 * `flash(keys, durationMs)` adds them and removes each after its duration.
 * Shared by row flash (keys = row ids) and cell flash (keys = `flashCellKey`).
 */
function useFlashSet(): [
  ReadonlySet<string>,
  (keys: string[], durationMs: number) => void,
] {
  const [set, setSet] = React.useState<Set<string>>(() => new Set())
  const timers = React.useRef<Map<string, ReturnType<typeof setTimeout>>>(
    new Map(),
  )
  React.useEffect(() => {
    const t = timers.current
    return () => {
      t.forEach(timer => clearTimeout(timer))
      t.clear()
    }
  }, [])
  const flash = useCallback((keys: string[], durationMs: number) => {
    if (keys.length === 0) return
    setSet(prev => {
      const next = new Set(prev)
      for (const k of keys) next.add(k)
      return next
    })
    for (const k of keys) {
      const existing = timers.current.get(k)
      if (existing) clearTimeout(existing)
      timers.current.set(
        k,
        setTimeout(() => {
          setSet(prev => {
            if (!prev.has(k)) return prev
            const next = new Set(prev)
            next.delete(k)
            return next
          })
          timers.current.delete(k)
        }, durationMs),
      )
    }
  }, [])
  return [set, flash]
}

export function DataTableProvider<TData>({
  children,
  table,
  columns,
  isLoading: externalIsLoading,
}: DataTableProviderProps<TData>) {
  const [state, dispatch] = useReducer(
    dataTableReducer,
    deriveInitialState(externalIsLoading),
  )

  const setIsLoading = useCallback((value: boolean) => {
    dispatch({
      type: DataTableActions.SET_IS_LOADING,
      value,
    })
  }, [])

  // Narrow, virtualizer-agnostic scroll bridge. The virtualized body registers
  // its `scrollToIndex` here; `scrollRowIntoView` calls through it, or falls
  // back to a DOM query for non-virtualized bodies. Both callbacks are stable.
  const rowScrollerRef = React.useRef<ScrollRowIntoView | null>(null)
  const registerRowScroller = useCallback((fn: ScrollRowIntoView | null) => {
    rowScrollerRef.current = fn
  }, [])
  const scrollRowIntoView = useCallback<ScrollRowIntoView>((index, opts) => {
    if (rowScrollerRef.current) {
      rowScrollerRef.current(index, opts)
      return
    }
    if (typeof document !== "undefined") {
      // Virtualized rows carry `data-index`; plain body rows carry
      // `data-row-index` — match either so the DOM fallback works for both.
      // Map the virtualizer-style `align` onto scrollIntoView's `block`.
      const block: ScrollLogicalPosition =
        opts?.align === undefined || opts.align === "auto"
          ? "nearest"
          : opts.align
      document
        .querySelector(`[data-index="${index}"], [data-row-index="${index}"]`)
        ?.scrollIntoView({ block })
    }
  }, [])

  // Row / cell flash — highlight-what-changed. Two identity sets (rows by id,
  // cells by `flashCellKey`) with per-key timers so overlapping flashes each get
  // their full duration; the body plays a fade pulse on matching cells.
  const [flashingRowIds, flashRowKeys] = useFlashSet()
  const [flashingCellKeys, flashCellKeys] = useFlashSet()

  // Active-cell cross-highlight (grid-style) — provided through its own
  // context pair (see above) so per-keystroke updates in an editable grid
  // don't churn the main context value. `setActiveCell` is stable.
  const [activeCell, setActiveCell] = React.useState<ActiveCell>(null)

  // Anchor for Shift-range row selection. Ref, not state — it's
  // read/written only inside the click handler, never rendered.
  const rowSelectionAnchorRef = React.useRef<string | null>(null)
  const toggleRowSelection = useCallback(
    (rowId: string, shiftKey: boolean) => {
      const model = table.getRowModel()
      const row = model.rowsById[rowId]
      if (!row) return
      const anchorId = rowSelectionAnchorRef.current
      if (shiftKey && anchorId != null && model.rowsById[anchorId]) {
        // Select every row between the anchor and this one in DISPLAY order.
        // Use positions in `model.rows` — TanStack's `row.index` is the
        // source-data index and diverges after sort/filter.
        const a = model.rows.findIndex(r => r.id === anchorId)
        const b = model.rows.findIndex(r => r.id === rowId)
        if (a === -1 || b === -1) return
        const next = { ...table.getState().rowSelection }
        for (let i = Math.min(a, b); i <= Math.max(a, b); i++) {
          const r = model.rows[i]
          if (r?.getCanSelect()) next[r.id] = true
        }
        table.setRowSelection(next)
        return
      }
      row.toggleSelected()
      rowSelectionAnchorRef.current = rowId
    },
    [table],
  )

  const scrollFirstIdIntoView = useCallback(
    (ids: string[]) => {
      const model = table.getRowModel()
      for (const id of ids) {
        // Display index — `scrollRowIntoView` / the virtualizer speak display
        // space, not TanStack's source-data `row.index`.
        const idx = model.rows.findIndex(r => r.id === id)
        if (idx !== -1) {
          scrollRowIntoView(idx, { align: "center" })
          return
        }
      }
    },
    [table, scrollRowIntoView],
  )

  const flashRows = useCallback<FlashRows>(
    (ids, opts) => {
      if (ids.length === 0) return
      if (opts?.scrollIntoView ?? true) scrollFirstIdIntoView(ids)
      flashRowKeys(ids, opts?.durationMs ?? 1400)
    },
    [flashRowKeys, scrollFirstIdIntoView],
  )

  const flashCells = useCallback<FlashCells>(
    (cells, opts) => {
      if (cells.length === 0) return
      if (opts?.scrollIntoView ?? true)
        scrollFirstIdIntoView(cells.map(c => c.rowId))
      flashCellKeys(
        cells.map(c => flashCellKey(c.rowId, c.columnId)),
        opts?.durationMs ?? 1400,
      )
    },
    [flashCellKeys, scrollFirstIdIntoView],
  )

  /**
   * Derive `isLoading` at READ time, not via a sync useEffect.
   *
   * WHY: The previous pattern — `useEffect(() => setIsLoading(externalIsLoading))`
   * — is a "copy prop into state" anti-pattern. Under React 19 + Next.js 16
   * (Turbopack), it can schedule a reducer dispatch that lands on an unmounted
   * component instance during HMR or Strict Mode double-mount, producing:
   *
   *   "Can't perform a React state update on a component that hasn't mounted
   *   yet. This indicates that you have a side-effect in your render function
   *   that asynchronously tries to update the component."
   *
   * FIX: When `externalIsLoading` is provided it wins (matches the original
   * effect's intent); otherwise fall back to the reducer-managed state.
   * No cross-commit dispatch, no race, no unmount-target warning.
   *
   * BEHAVIOR NOTE: If a caller both passes `isLoading` as a prop AND calls
   * `setIsLoading()` from inside the tree, the prop wins and the internal
   * call becomes a no-op. This matches the documented contract of a
   * controlled prop and was already the intended behavior of the effect.
   */
  const effectiveIsLoading = externalIsLoading ?? state.isLoading

  // Table instance ref is stable across state changes — extract individual
  // state slices so context consumers re-render on filter/sort/select.
  const tableState = table.getState()

  const globalFilter = tableState.globalFilter
  const sorting = tableState.sorting
  const columnFilters = tableState.columnFilters
  const columnVisibility = tableState.columnVisibility
  const expanded = tableState.expanded
  const rowSelection = tableState.rowSelection
  const pagination = tableState.pagination
  const columnPinning = tableState.columnPinning
  const columnOrder = tableState.columnOrder
  const columnSizing = tableState.columnSizing

  // Lightweight state hash beats JSON.stringify for large selections
  // (~0.1ms vs 20-50ms at 1k rows) while still triggering consumer updates.
  const tableStateKey = React.useMemo(() => {
    // Full sorted-keys hash — a "first 3 keys" signature collided on
    // sequential row IDs (`r1,r2,r3` vs `r1,r2,r4`).
    const getObjectHash = (
      obj: Record<string, unknown> | undefined,
    ): string => {
      if (!obj) return "0"
      const keys = Object.keys(obj)
      if (keys.length === 0) return "0"
      return keys.sort().join(",")
    }

    const paginationKey = `${pagination.pageIndex ?? 0}:${pagination.pageSize ?? 0}`

    // Handle globalFilter - can be string or object (for complex filters)
    const globalFilterHash =
      typeof globalFilter === "string"
        ? globalFilter
        : globalFilter && typeof globalFilter === "object"
          ? getObjectHash(globalFilter)
          : ""

    return {
      globalFilter: globalFilterHash,
      sortingHash: JSON.stringify(sorting),
      columnFiltersHash: JSON.stringify(columnFilters),
      columnVisibilityHash: getObjectHash(
        columnVisibility as Record<string, unknown> | undefined,
      ),
      expandedHash: getObjectHash(
        expanded as Record<string, unknown> | undefined,
      ),
      rowSelectionHash: getObjectHash(
        rowSelection as Record<string, unknown> | undefined,
      ),
      paginationKey,
      columnPinningHash: JSON.stringify(columnPinning),
      columnOrderHash: JSON.stringify(columnOrder),
      // Column widths — so a resize re-runs the context value memo and the
      // memoized header/body pick up the new `column.getSize()`.
      columnSizingHash: JSON.stringify(columnSizing),
    }
  }, [
    globalFilter,
    sorting,
    columnFilters,
    columnVisibility,
    expanded,
    rowSelection,
    pagination,
    columnPinning,
    columnOrder,
    columnSizing,
  ])

  // Generate options for all select/multiSelect columns in a single pass.
  // This replaces N separate per-column scans in faceted filter consumers.
  const generatedOptionsMap = useGeneratedOptions(table)

  // Memoize so context consumers (10+ filter/action components) only re-render
  // when table, columns, loading, or actual table state changes.
  const value = React.useMemo(
    () =>
      ({
        table,
        columns:
          columns || (table.options.columns as DataTableColumnDef<TData>[]),
        isLoading: effectiveIsLoading,
        generatedOptionsMap,
        setIsLoading,
        scrollRowIntoView,
        registerRowScroller,
        flashingRowIds,
        flashingCellKeys,
        flashRows,
        flashCells,
        toggleRowSelection,
      }) as DataTableContextProps<TData>,
    // eslint-disable-next-line react-hooks/exhaustive-deps -- tableStateKey is load-bearing for reactivity (see block comment above)
    [
      table,
      columns,
      effectiveIsLoading,
      generatedOptionsMap,
      setIsLoading,
      scrollRowIntoView,
      registerRowScroller,
      flashingRowIds,
      flashingCellKeys,
      flashRows,
      flashCells,
      toggleRowSelection,
      tableStateKey,
    ],
  )

  return (
    <DataTableContext.Provider value={value}>
      <ActiveCellSetterContext.Provider value={setActiveCell}>
        <ActiveCellValueContext.Provider value={activeCell}>
          <style href="niko-row-flash" precedence="default">
            {ROW_FLASH_KEYFRAMES}
          </style>
          {children}
        </ActiveCellValueContext.Provider>
      </ActiveCellSetterContext.Provider>
    </DataTableContext.Provider>
  )
}

/**
 * Self-contained flash animation (no dependency on app globals). Soft fade
 * pulse: a primary-tinted background fades to transparent once, ~1.2s.
 */
const ROW_FLASH_KEYFRAMES = `@keyframes niko-row-flash {
  0% { background-color: color-mix(in oklab, var(--primary) 24%, transparent); }
  100% { background-color: transparent; }
}`

export { DataTableContext }

"use client"

/**
 * niko-table — created by Semir N. (Semkoo, https://github.com/Semkoo) with AI assistance.
 *
 * Before reporting anything: please check the changelog first.
 *  - In-repo: ./CHANGELOG.md
