/**
 * Drag-to-resize / double-click-to-autosize grip used by DataTableHeader and
 * DataTableVirtualizedHeader when `enableColumnResizing` is on. Lives in core
 * so both bodies can import it without pulling the opt-in marker package.
 */
import { type Header } from "@tanstack/react-table"
import { cn } from "@/lib/utils"
import { DEFAULT_MAX_COLUMN_SIZE, DEFAULT_MIN_COLUMN_SIZE } from "./constants"

/** Room for cell chrome the text measurement doesn't cover. */
const AUTOSIZE_CELL_PADDING = 24 // horizontal padding + buffer
const AUTOSIZE_HEADER_CHROME = 52 // sort/menu trigger + resize grip

/** Re-export for consumers that imported sizes from this module. */
export { DEFAULT_MAX_COLUMN_SIZE, DEFAULT_MIN_COLUMN_SIZE }

/** Keyboard resize step (px); the larger step applies while Shift is held. */
const KEYBOARD_RESIZE_STEP = 8
const KEYBOARD_RESIZE_STEP_LARGE = 40

/**
 * Tightest width that fits every TEXT node in an element. Uses a DOM Range
 * so `w-full` + `truncate` wrappers — whose `scrollWidth` echoes the current
 * cell width — don't hide the natural content width. Autosize can grow AND
 * shrink to fit.
 */
function widestTextWidth(el: Element): number {
  const range = document.createRange()
  const walker = document.createTreeWalker(el, NodeFilter.SHOW_TEXT)
  let max = 0
  for (let n = walker.nextNode(); n; n = walker.nextNode()) {
    if (!n.textContent || n.textContent.trim() === "") continue
    range.selectNodeContents(n)
    max = Math.max(max, range.getBoundingClientRect().width)
  }
  return max
}

/**
 * Autosize a column to fit its content — measures the widest rendered
 * cell/header text (mounted cells only — for virtualized tables, what's on
 * screen) and sets that column's size.
 */
function autosizeColumn<TData>(
  header: Header<TData, unknown>,
  handle: Element,
) {
  const root = handle.closest('[data-slot="table"]')
  if (!root) return
  const cells = root.querySelectorAll<HTMLElement>(
    `[data-col-id="${CSS.escape(header.column.id)}"]`,
  )
  let content = 0
  cells.forEach(c => {
    const isHeader = c.getAttribute("data-slot") === "table-head"
    const chrome = isHeader ? AUTOSIZE_HEADER_CHROME : AUTOSIZE_CELL_PADDING
    content = Math.max(content, widestTextWidth(c) + chrome)
  })
  if (content <= 0) return
  const def = header.column.columnDef
  const width = Math.min(
    Math.max(Math.ceil(content), def.minSize ?? DEFAULT_MIN_COLUMN_SIZE),
    def.maxSize ?? DEFAULT_MAX_COLUMN_SIZE,
  )
  header
    .getContext()
    .table.setColumnSizing(prev => ({ ...prev, [header.column.id]: width }))
}

/**
 * Drag-to-resize / double-click-to-autosize grip on a header's right edge.
 * Keyboard-operable (WAI-ARIA window-splitter): focusable, Arrow Left/Right
 * nudge the width (Shift = larger step), Enter autosizes; exposes
 * `aria-value*`.
 */
export interface DataTableColumnResizeHandleProps<TData> {
  header: Header<TData, unknown>
}

export function DataTableColumnResizeHandle<TData>({
  header,
}: DataTableColumnResizeHandleProps<TData>) {
  const isResizing = header.column.getIsResizing()
  const resize = header.getResizeHandler()
  const def = header.column.columnDef
  const min = def.minSize ?? DEFAULT_MIN_COLUMN_SIZE
  const max = def.maxSize ?? DEFAULT_MAX_COLUMN_SIZE

  const nudge = (delta: number) => {
    header.getContext().table.setColumnSizing(prev => {
      const current = prev[header.column.id] ?? header.column.getSize()
      const next = Math.min(Math.max(current + delta, min), max)
      return { ...prev, [header.column.id]: next }
    })
  }

  return (
    <div
      data-slot="column-resize-handle"
      role="separator"
      aria-orientation="vertical"
      aria-label="Resize column (arrow keys, or double-click to fit)"
      aria-valuenow={header.column.getSize()}
      aria-valuemin={min}
      aria-valuemax={max}
      tabIndex={0}
      onMouseDown={e => {
        // Keep column-DnD header listeners from treating a resize drag as a
        // reorder start (handle lives inside the sortable `<th>`).
        e.stopPropagation()
        resize(e)
      }}
      onTouchStart={e => {
        e.stopPropagation()
        resize(e)
      }}
      onDoubleClick={e => autosizeColumn(header, e.currentTarget)}
      onClick={e => e.stopPropagation()}
      onPointerDown={e => e.stopPropagation()}
      onKeyDown={e => {
        const step = e.shiftKey
          ? KEYBOARD_RESIZE_STEP_LARGE
          : KEYBOARD_RESIZE_STEP
        if (e.key === "ArrowLeft") {
          e.preventDefault()
          nudge(-step)
        } else if (e.key === "ArrowRight") {
          e.preventDefault()
          nudge(step)
        } else if (e.key === "Enter") {
          e.preventDefault()
          autosizeColumn(header, e.currentTarget)
        }
      }}
      className="group/resize absolute top-0 right-0 z-10 flex h-full w-2 cursor-col-resize touch-none justify-end outline-none select-none"
    >
      {/* Faint grip always visible (discoverable); a full primary bar on
          hover, keyboard focus, or active drag. */}
      <div
        className={cn(
          "my-1.5 w-px rounded bg-border transition-all",
          "group-hover/resize:my-0 group-hover/resize:w-0.5 group-hover/resize:bg-primary",
          "group-focus-visible/resize:my-0 group-focus-visible/resize:w-0.5 group-focus-visible/resize:bg-primary",
          isResizing && "my-0 w-0.5 bg-primary",
        )}
      />
    </div>
  )
}

"use client"

import * as React from "react"

import {
  ContextMenu,
  ContextMenuContent,
  ContextMenuTrigger,
} from "@/components/ui/context-menu"

import { DataTableRowMenuScope } from "./data-table-row-menu"

export interface DataTableRowContextMenuProps {
  /**
   * The row's `original` data. Provided to the menu children via
   * `DataTableRowMenuScope` so a declarative `<XRowMenu>` can read it with
   * `useDataTableRow()` and render the same items as the kebab dropdown.
   */
  row: unknown
  /**
   * The `<TableRow>` element the menu anchors to. Radix's `asChild` merges
   * the right-click listener onto this element (via Slot), so no wrapper
   * node is introduced and table markup (`<tbody> > <tr>`) stays valid.
   */
  trigger: React.ReactElement
  /**
   * The menu items to show on right-click — compose `ContextMenuItem`,
   * `ContextMenuSeparator`, `ContextMenuSub`, etc. The portal + surface
   * chrome is owned here so callers only supply the actions.
   *
   * Tip: reuse the same items your row's "…" actions column renders so
   * right-click and the kebab menu stay in sync (write once).
   */
  children: React.ReactNode
  /** Extra className for the popup surface. */
  className?: string
}

/**
 * Attaches a right-click context menu to a single data-table row.
 *
 * Low-level primitive used internally by the bodies (and directly by card
 * views): pass the row's data as `row`, the row's `<TableRow>` element as
 * `trigger`, and the menu as `children`. Children are wrapped in a
 * `DataTableRowMenuScope surface="context"`, so a declarative `<XRowMenu>`
 * built from `RowMenuItem`/… (see `data-table-row-menu`) works here — as do
 * raw `ContextMenuItem`s. The popup is portalled and only mounts on open.
 *
 * @example
 * <DataTableRowContextMenu
 *   row={row.original}
 *   trigger={<TableRow data-row-id={row.id}>{cells}</TableRow>}
 * >
 *   <PlayerRowMenu onView={view} onRemove={remove} />
 * </DataTableRowContextMenu>
 */
export function DataTableRowContextMenu({
  row,
  trigger,
  children,
  className,
}: DataTableRowContextMenuProps) {
  // Keep the anchored row visually highlighted while its menu is open, so the
  // user can see which row they're acting on. We stamp `data-context-menu-open`
  // on the row element; the table's row/cell styles react to it the same way
  // they react to `data-state="selected"`.
  const [open, setOpen] = React.useState(false)
  const anchoredTrigger = open
    ? React.cloneElement(
        trigger as React.ReactElement<{ "data-context-menu-open"?: string }>,
        { "data-context-menu-open": "" },
      )
    : trigger

  return (
    <ContextMenu onOpenChange={setOpen}>
      <ContextMenuTrigger asChild>{anchoredTrigger}</ContextMenuTrigger>
      <ContextMenuContent className={className}>
        <DataTableRowMenuScope row={row} surface="context">
          {children}
        </DataTableRowMenuScope>
      </ContextMenuContent>
    </ContextMenu>
  )
}

DataTableRowContextMenu.displayName = "DataTableRowContextMenu"

"use client"

import * as React from "react"

export interface DataTableRowContextMenuSlotProps<TData> {
  /**
   * The row menu. Preferred (shadcn/composable) form is a declarative
   * component that reads the row via `useDataTableRow()`:
   *
   *   <DataTableRowContextMenuSlot>
   *     <TeamRowMenu onEdit={…} onDelete={…} />
   *   </DataTableRowContextMenuSlot>
   *
   * A `(row) => menu` function is also accepted for cases that would rather
   * close over the row explicitly.
   */
  children: React.ReactNode | ((row: TData) => React.ReactNode)
  /**
   * Optional per-row predicate — return `false` to give a specific row no
   * menu (e.g. locked/browse-only rows). Table-level gating (e.g. "no manage
   * permission") is better done by simply not rendering the slot at all.
   */
  enabledFor?: (row: TData) => boolean
}

/**
 * Declarative, composable row context menu for niko-table bodies.
 *
 * Nest it inside a `DataTableBody` / `DataTableVirtualizedBody` — or any of
 * the four DnD bodies (`DataTableDndBody`, `DataTableDndColumnBody`,
 * `DataTableVirtualizedDndBody`, `DataTableVirtualizedDndColumnBody`) — so
 * the per-row menu reads as part of the table's JSX tree. It renders nothing
 * itself — the body detects it among its children and renders its menu for
 * every (enabled) row inside a `DataTableRowMenuScope`, so a declarative
 * `<XRowMenu>` composed from `RowMenuItem` / `RowMenuSub` / … resolves the
 * row and surface from context. The body's `renderRowContextMenu` prop still
 * works and wins when both are present.
 *
 * @example
 * <DataTableVirtualizedBody estimateSize={44}>
 *   <DataTableRowContextMenuSlot enabledFor={(m) => !m.isLocked}>
 *     <PoolRowMenu onOffer={…} onDirectAssign={…} />
 *   </DataTableRowContextMenuSlot>
 *   <DataTableVirtualizedSkeleton rows={8} />
 * </DataTableVirtualizedBody>
 */
export function DataTableRowContextMenuSlot<TData>(
  _props: DataTableRowContextMenuSlotProps<TData>,
): null {
  return null
}
DataTableRowContextMenuSlot.displayName = "DataTableRowContextMenuSlot"

/**
 * Resolve the effective per-row menu renderer for a body: the explicit
 * `renderRowContextMenu` prop wins; otherwise a nested
 * `<DataTableRowContextMenuSlot>` child (declarative node or function),
 * honouring its optional `enabledFor` predicate.
 */
export function resolveRowContextMenuRenderer<TData>(
  prop: ((row: TData) => React.ReactNode) | undefined,
  children: React.ReactNode,
): ((row: TData) => React.ReactNode) | undefined {
  if (prop) return prop

  let slotProps: DataTableRowContextMenuSlotProps<TData> | undefined
  React.Children.forEach(children, child => {
    if (!React.isValidElement(child)) return
    // Match by displayName — reference equality breaks across re-exports / HMR.
    const type = child.type as { displayName?: string }
    if (
      child.type === DataTableRowContextMenuSlot ||
      type.displayName === "DataTableRowContextMenuSlot"
    ) {
      slotProps = child.props as DataTableRowContextMenuSlotProps<TData>
    }
  })
  if (!slotProps) return undefined

  const { children: menu, enabledFor } = slotProps
  return (row: TData) => {
    if (enabledFor && !enabledFor(row)) return null
    return typeof menu === "function"
      ? (menu as (row: TData) => React.ReactNode)(row)
      : menu
  }
}

/**
 * Body-side hook: resolve the per-row menu renderer and return a **stable**
 * callback identity, so memoized rows (`BodyRow`) don't re-render just because
 * the body re-rendered. `resolveRowContextMenuRenderer` returns a fresh
 * function each render (it closes over `children`); we keep the latest in a ref
 * and hand out a stable wrapper that reads it. The wrapper identity only
 * changes when the presence of a menu changes.
 */
export function useResolvedRowContextMenuRenderer<TData>(
  prop: ((row: TData) => React.ReactNode) | undefined,
  children: React.ReactNode,
): ((row: TData) => React.ReactNode) | undefined {
  const resolved = resolveRowContextMenuRenderer(prop, children)
  const latestRef = React.useRef(resolved)

  latestRef.current = resolved
  const hasMenu = !!resolved
  return React.useMemo(
    () => (hasMenu ? (row: TData) => latestRef.current?.(row) : undefined),
    [hasMenu],
  )
}

"use client"

import * as React from "react"

import {
  ContextMenuGroup,
  ContextMenuItem,
  ContextMenuLabel,
  ContextMenuSeparator,
  ContextMenuSub,
  ContextMenuSubContent,
  ContextMenuSubTrigger,
} from "@/components/ui/context-menu"
import {
  DropdownMenuGroup,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuSub,
  DropdownMenuSubContent,
  DropdownMenuSubTrigger,
} from "@/components/ui/dropdown-menu"

/**
 * Composable row menu for niko-table — the shadcn-style, write-once way to give
 * a table's "…" dropdown and its right-click context menu the *same* actions.
 *
 * Define the actions ONCE as a component using the polymorphic `RowMenuItem` /
 * `RowMenuSeparator` / `RowMenuSub` … pieces and `useDataTableRow()`:
 *
 * @example
 * function TeamRowMenu({ onEdit, onDelete }: TeamRowMenuProps) {
 *   const team = useDataTableRow<TeamRow>()
 *   return (
 *     <>
 *       <RowMenuItem onClick={() => onEdit(team)}>Edit</RowMenuItem>
 *       <RowMenuSeparator />
 *       <RowMenuItem variant="destructive" onClick={() => onDelete(team.id)}>
 *         Delete
 *       </RowMenuItem>
 *     </>
 *   )
 * }
 *
 * Then drop `<TeamRowMenu … />` into the kebab cell (inside a
 * `DataTableRowMenuScope surface="dropdown"`) and into the body's
 * `<DataTableRowContextMenuSlot>` — the same component renders as a dropdown
 * menu or a context menu depending on the surface it finds in context.
 */

type RowMenuSurface = "dropdown" | "context"

const RowMenuSurfaceContext = React.createContext<RowMenuSurface | null>(null)

/** Sentinel so `useDataTableRow` can tell "no provider" from a row of `undefined`. */
const NO_ROW = Symbol("niko-table.no-row")
const DataTableRowValueContext = React.createContext<unknown>(NO_ROW)

/**
 * Provides the current row and the menu surface to the row-menu pieces nested
 * inside. The context-menu body sets this up automatically; kebab cells wrap
 * their `DropdownMenuContent` children with `surface="dropdown"`.
 */
export function DataTableRowMenuScope({
  row,
  surface,
  children,
}: {
  row: unknown
  surface: RowMenuSurface
  children: React.ReactNode
}) {
  return (
    <RowMenuSurfaceContext.Provider value={surface}>
      <DataTableRowValueContext.Provider value={row}>
        {children}
      </DataTableRowValueContext.Provider>
    </RowMenuSurfaceContext.Provider>
  )
}

/** Read the row a row-menu is rendering for. Throws outside a scope. */
export function useDataTableRow<TData>(): TData {
  const row = React.useContext(DataTableRowValueContext)
  if (row === NO_ROW) {
    throw new Error(
      'useDataTableRow must be used inside a DataTableRowMenuScope — i.e. a table row context menu, or a kebab DropdownMenuContent wrapped with surface="dropdown".',
    )
  }
  return row as TData
}

function useRowMenuSurface(): RowMenuSurface {
  const surface = React.useContext(RowMenuSurfaceContext)
  if (!surface) {
    throw new Error(
      'Row menu pieces (RowMenuItem, RowMenuSub, …) must be rendered inside a DataTableRowMenuScope — i.e. a table row context menu or a kebab DropdownMenuContent wrapped with surface="dropdown".',
    )
  }
  return surface
}

// ---------------------------------------------------------------------------
// Polymorphic pieces — render the dropdown or context primitive by surface.
// ---------------------------------------------------------------------------

export function RowMenuItem(
  props: React.ComponentProps<typeof DropdownMenuItem>,
) {
  const Item =
    useRowMenuSurface() === "context" ? ContextMenuItem : DropdownMenuItem
  return <Item {...props} />
}

export function RowMenuSeparator(
  props: React.ComponentProps<typeof DropdownMenuSeparator>,
) {
  const Separator =
    useRowMenuSurface() === "context"
      ? ContextMenuSeparator
      : DropdownMenuSeparator
  return <Separator {...props} />
}

export function RowMenuGroup(
  props: React.ComponentProps<typeof DropdownMenuGroup>,
) {
  const Group =
    useRowMenuSurface() === "context" ? ContextMenuGroup : DropdownMenuGroup
  return <Group {...props} />
}

export function RowMenuLabel(
  props: React.ComponentProps<typeof DropdownMenuLabel>,
) {
  const Label =
    useRowMenuSurface() === "context" ? ContextMenuLabel : DropdownMenuLabel
  return <Label {...props} />
}

export function RowMenuSub(
  props: React.ComponentProps<typeof DropdownMenuSub>,
) {
  const Sub =
    useRowMenuSurface() === "context" ? ContextMenuSub : DropdownMenuSub
  return <Sub {...props} />
}

export function RowMenuSubTrigger(
  props: React.ComponentProps<typeof DropdownMenuSubTrigger>,
) {
  const SubTrigger =
    useRowMenuSurface() === "context"
      ? ContextMenuSubTrigger
      : DropdownMenuSubTrigger
  return <SubTrigger {...props} />
}

export function RowMenuSubContent(
  props: React.ComponentProps<typeof DropdownMenuSubContent>,
) {
  const SubContent =
    useRowMenuSurface() === "context"
      ? ContextMenuSubContent
      : DropdownMenuSubContent
  return <SubContent {...props} />
}

